// =============================================================================
// Preparação de Dados Sazonais — BACKTEST
//
// Diferença vs versão de produção:
//   - Aceita uma data de referência ARBITRÁRIA vinda do webhook (`referenceDate`)
//   - Para essa data, só considera histórico STRITAMENTE ANTERIOR ao mês alvo
//   - Pode receber múltiplos meses-alvo de uma vez (`targetMonths` no webhook).
// Webhook input shape (passa pelo "Set Reference"):
//   { targetMonths: ["YYYY-MM", "YYYY-MM", ...] }
// Cada SKU é avaliado para cada targetMonth.
// =============================================================================

const WINDOW_OFFSET = 2;

// Recupera a configuração do webhook (vem como item extra no input)
const webhookData = $("Webhook").first().json;
const body = webhookData.body || webhookData;
let targetMonths = body.targetMonths;
if (!Array.isArray(targetMonths) || targetMonths.length === 0) {
  // Default: backtest dos últimos 3 meses presentes
  targetMonths = [];
}

// --- Chunking por SKU (para não sobrecarregar o task-runner do n8n) ---
const skuOffset = Number.isFinite(Number(body.skuOffset)) ? Math.max(0, parseInt(body.skuOffset, 10)) : 0;
const skuLimitRaw = Number.isFinite(Number(body.skuLimit)) ? parseInt(body.skuLimit, 10) : 0;
const skuLimit = skuLimitRaw > 0 ? skuLimitRaw : 0;

// Coleta SKUs vindos do Merge Payload
const skuItemsAll = [];
for (const item of $input.all()) {
  const list = item.json.columns || [item.json];
  for (const sku of list) skuItemsAll.push(sku);
}
const totalSkus = skuItemsAll.length;
const skuItems = skuLimit > 0
  ? skuItemsAll.slice(skuOffset, skuOffset + skuLimit)
  : skuItemsAll.slice(skuOffset);

// Se não passou targetMonths, escolhe automaticamente os 3 últimos meses presentes
if (targetMonths.length === 0) {
  const found = new Set();
  for (const sku of skuItems) {
    for (const k of Object.keys(sku)) {
      if (/^\d{4}-\d{2}$/.test(k) && sku[k] != null && !isNaN(Number(sku[k]))) {
        found.add(k);
      }
    }
  }
  const sorted = [...found].sort();
  targetMonths = sorted.slice(-3);
}

const results = [];

for (const targetMonth of targetMonths) {
  const m = targetMonth.match(/^(\d{4})-(\d{2})$/);
  if (!m) continue;
  const targetYear = parseInt(m[1], 10);
  const targetMonthNum = parseInt(m[2], 10);

  // Para cada SKU, monta a janela sazonal CONSIDERANDO apenas histórico < target
  for (const sku of skuItems) {
    const skuCode = sku.SKU;
    const description = sku["Descrição"];
    const formato = sku.Formato;

    const salesByYearMonth = {};
    const allYears = new Set();
    let realValue = null;
    let monthsAvailable = 0;

    for (const key of Object.keys(sku)) {
      const km = key.match(/^(\d{4})-(\d{2})$/);
      if (!km) continue;
      const v = sku[key];
      if (v == null || v === "" || isNaN(Number(v))) continue;
      const y = parseInt(km[1], 10);
      const mm = parseInt(km[2], 10);
      const numericValue = Number(v);

      if (y === targetYear && mm === targetMonthNum) {
        realValue = numericValue;
        continue; // não usar como histórico
      }
      // Apenas histórico ESTRITAMENTE anterior ao mês alvo
      if (y < targetYear || (y === targetYear && mm < targetMonthNum)) {
        if (!salesByYearMonth[y]) salesByYearMonth[y] = {};
        salesByYearMonth[y][mm] = numericValue;
        allYears.add(y);
        monthsAvailable++;
      }
    }

    const sortedYears = [...allYears].sort((a, b) => a - b);

    // Janela
    const windowMonths = [];
    for (let off = -WINDOW_OFFSET; off <= WINDOW_OFFSET; off++) {
      let wm = targetMonthNum + off;
      if (wm < 1) wm += 12;
      if (wm > 12) wm -= 12;
      windowMonths.push(wm);
    }
    const historicalYears = sortedYears.filter((y) => y < targetYear);
    const historicalData = {};
    for (const year of historicalYears) {
      const yd = {};
      for (const wm of windowMonths) {
        if (
          salesByYearMonth[year] &&
          salesByYearMonth[year][wm] !== undefined
        ) {
          yd[`${year}-${String(wm).padStart(2, "0")}`] =
            salesByYearMonth[year][wm];
        }
      }
      if (Object.keys(yd).length) historicalData[year] = yd;
    }
    const targetMonthHistory = [];
    for (const year of historicalYears) {
      if (
        salesByYearMonth[year] &&
        salesByYearMonth[year][targetMonthNum] !== undefined
      ) {
        targetMonthHistory.push({
          year,
          value: salesByYearMonth[year][targetMonthNum],
        });
      }
    }
    const recentMonths = [];
    let ry = targetYear,
      rm = targetMonthNum - 1;
    if (rm < 1) {
      rm = 12;
      ry--;
    }
    for (let i = 0; i < 6; i++) {
      if (salesByYearMonth[ry] && salesByYearMonth[ry][rm] !== undefined) {
        recentMonths.push({
          key: `${ry}-${String(rm).padStart(2, "0")}`,
          value: salesByYearMonth[ry][rm],
        });
      }
      rm--;
      if (rm < 1) {
        rm = 12;
        ry--;
      }
    }

    const values = targetMonthHistory.map((v) => v.value);
    const n = values.length;
    const mean = n > 0 ? values.reduce((a, b) => a + b, 0) / n : 0;
    const variance =
      n > 1
        ? values.reduce((s, v) => s + Math.pow(v - mean, 2), 0) / (n - 1)
        : 0;
    const stdDev = Math.sqrt(variance);

    const insufficientHistory = monthsAvailable < 2;
    const seasonalWindows = {};
    seasonalWindows[targetMonth] = {
      windowMonths: windowMonths.map((m) => String(m).padStart(2, "0")),
      historicalYears,
      historicalData,
      targetMonthHistory,
      recentMonths,
      statistics: {
        mean: parseFloat(mean.toFixed(3)),
        stdDev: parseFloat(stdDev.toFixed(3)),
        confidenceInterval: {
          lower: parseFloat(Math.max(0, mean - stdDev).toFixed(3)),
          upper: parseFloat((mean + stdDev).toFixed(3)),
        },
        sampleSize: n,
      },
      windowStatistics: { mean: 0, stdDev: 0, sampleSize: 0 },
    };

    results.push({
      SKU: skuCode,
      Descrição: description,
      Formato: formato,
      backtestTarget: targetMonth,
      realValue,
      historyMonthsAvailable: monthsAvailable,
      insufficientHistory,
      monthsMissingForMin: Math.max(0, 2 - monthsAvailable),
      dataReferencia: targetMonth + "-01",
      seasonalWindows,
    });
  }
}

return { analysis: results, targetMonths, totalSkus, skuOffset, skuLimit };

