// =============================================================================
// Backtest Compare — junta previsão (do Python) com valor real (do JS prep)
// e calcula o erro percentual. Devolve um array para a planilha de saída.
// =============================================================================

const rows = [];
let targetMonths = null;

for (const item of $input.all()) {
  const data = item.json;
  if (!targetMonths && data._targetMonths) targetMonths = data._targetMonths;

  const target =
    data.backtestTarget ||
    (data.previsoes && data.previsoes[0] && data.previsoes[0].mes);
  if (!target) continue;

  const prev =
    (data.previsoes || []).find((p) => p.mes === target) || data.previsoes?.[0];
  const previsao = prev ? prev.previsao : 0;
  const tolerancePct = prev ? prev.tolerancePct || 0 : 0;
  const real = data.realValue;

  let errorAbs = null,
    errorPct = null,
    dentroDaTolerancia = null;
  if (real != null && real !== 0) {
    errorAbs = Math.abs(previsao - real);
    errorPct = parseFloat(((errorAbs / Math.abs(real)) * 100).toFixed(2));
    dentroDaTolerancia = errorPct <= tolerancePct;
  }

  rows.push({
    json: {
      mes: target,
      SKU: data.SKU,
      Descrição: data["Descrição"],
      Formato: data.Formato || "",
      previsto: previsao,
      real: real,
      errorAbs,
      errorPct,
      tolerancePct,
      dentroDaTolerancia,
      tipo: prev ? prev.tipo : null,
      insufficientHistory: !!data.insufficientHistory,
    },
  });
}

return rows;

// =============================================================================
// Backtest Response — empacota as linhas + agrega MAPE/totais por mês.
// =============================================================================

const items = $input.all().map((d) => d.json);

// Lê metadados de chunk diretamente do node de preparação
let totalSkus = 0, skuOffset = 0, skuLimit = 0, targetMonths = null;
try {
  const prep = $("Preparação Sazonal Backtest").first().json;
  if (prep) {
    if (typeof prep.totalSkus === "number") totalSkus = prep.totalSkus;
    if (typeof prep.skuOffset === "number") skuOffset = prep.skuOffset;
    if (typeof prep.skuLimit === "number") skuLimit = prep.skuLimit;
    if (Array.isArray(prep.targetMonths)) targetMonths = prep.targetMonths;
  }
} catch (e) {}

const processed = items.length > 0 && targetMonths && targetMonths.length > 0
  ? Math.round(items.length / targetMonths.length)
  : items.length;
const nextOffset = skuOffset + processed;
const hasMore = totalSkus > 0 && nextOffset < totalSkus;

const byMonth = {};
for (const r of items) {
  if (!byMonth[r.mes])
    byMonth[r.mes] = { mes: r.mes, n: 0, mapeSum: 0, hits: 0, withinTol: 0 };
  byMonth[r.mes].n += 1;
  if (r.errorPct != null) {
    byMonth[r.mes].mapeSum += r.errorPct;
    byMonth[r.mes].hits += 1;
    if (r.dentroDaTolerancia) byMonth[r.mes].withinTol += 1;
  }
}

const summary = Object.values(byMonth)
  .map((s) => ({
    mes: s.mes,
    skus: s.n,
    skusComReal: s.hits,
    mape: s.hits ? parseFloat((s.mapeSum / s.hits).toFixed(2)) : null,
    pctDentroTolerancia: s.hits
      ? parseFloat(((s.withinTol / s.hits) * 100).toFixed(2))
      : null,
  }))
  .sort((a, b) => a.mes.localeCompare(b.mes));

return {
  data: items,
  summary,
  totalSkus,
  skuOffset,
  skuLimit,
  processedSkus: processed,
  nextOffset,
  hasMore,
  createdAt: $now,
};
